SELECT version_name 
FROM mapping_versions 
WHERE version_status = 'active';

SELECT mapping_id, created_date
FROM mappings
WHERE created_date > '2022-01-01';

SELECT COUNT(*) as total_lineages
FROM data_lineage
WHERE variable_id = 1;

SELECT COUNT(mapping_id) AS total_mappings
FROM mappings
WHERE created_by = 0;

SELECT created_by, COUNT(*) as num_mappings
FROM mapping_versions
GROUP BY created_by;

SELECT version_name, description
FROM variable_versions
WHERE variable_version_id = 0;

SELECT version_name, created_date
FROM variable_versions
WHERE status = 'active';

SELECT COUNT(*) AS active_versions_count
   FROM mapping_versions
   WHERE version_status = 'active';

SELECT DISTINCT version_name
FROM mapping_versions
WHERE version_status = 'active';

SELECT source_table, target_table
FROM data_lineage
WHERE source_column = 'ID';

SELECT created_by, COUNT(*) AS total_lineage_entries
FROM data_lineage
GROUP BY created_by;
